_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


//BACK
z = 1/(vUv.y-0.2 );
uv1 = vec2 (1*z*(vUv.x-0.5),z);
uv2 = uv1+q28 + vec2 (0,q2);

float noise = texture(sampler_rand00,uv2).r;
      noise -= texture(sampler_rand00,uv2+uTexSize.z*8).r*0.8;
      noise *= 1- (texture(sampler_rand00,noise*0.001+uv2*vec2(0.08,0.008)).r>0.85) * (z>=0)/z;
      noise *= (z >0) /z;

//STRUC
ret = GetPixel(vUv);
for (int n =1; n < iter; n++)
{
  ret = max(ret,GetPixel(vUv+uTexSize.zw*vec2(n,0)));
  ret = max(ret,GetPixel(vUv+uTexSize.zw*vec2(-n,0)));
}
mask = clamp01(1-16*lum(ret));


//LIGHT
ret *= (.1+.15/(length(vUv.y*8-lum(ret)*5)))*(1+roam_sin*0);
ret += noise*mask/5 ;

vec3 floorl = pow(length(vUv - vec2(q27+0.5,-0.5)),-2)* vec3 (0.4,0.8,1);

ret += (rand_preset/2)*2*pow(1-vUv.y,2)/4*mask;

ret += floorl * (.2+1*noise) * mask;

//GROUND REFL
ret += 64*GetBlur3(uv1*vec2(0.33,0.16)+vec2 (0.5,.10))*mask*clamp01(noise);


//ret += clamp01(1-8*pow(uv1.x+2*q27,2)) * (z>0)*8*noise/z;
//ret += clamp01(1-8*pow(uv1.x-2*q27,2)) * (z>0)*0.1;;

//FLASH
//ret += vUv.y*noise*q29;

//SHADOW
ret *= 1- lum(GetBlur1(uv1*vec2(0.5,0.37) +vec2(0.5  +q27/5,-.1))>0.02)*0.2;
ret *= 1- lum(GetBlur1(uv1*vec2(0.5,0.37) +vec2(0.505+q27/5,-.1))>0.02)*0.2;
ret *= 1- lum(GetBlur1(uv1*vec2(0.5,0.37) +vec2(0.51+q27/5,-.1))>0.02)*0.2;


  fragColor = ret;
}
